import{_ as t,o as a,c as n,ag as r}from"./chunks/framework.DXGyWiRo.js";const m=JSON.parse('{"title":"Theory (Paper 2)","description":"","frontmatter":{"title":"Theory (Paper 2)","nav_order":2,"has_children":true},"headers":[],"relativePath":"theory/index.md","filePath":"theory/index.md"}'),o={name:"theory/index.md"};function i(s,e,d,c,l,h){return a(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="theory-—-paper-2-overview" tabindex="-1">Theory — Paper 2 Overview <a class="header-anchor" href="#theory-—-paper-2-overview" aria-label="Permalink to &quot;Theory — Paper 2 Overview&quot;">​</a></h1><p>This section covers the six CAPS topics assessed in the <strong>Paper 2 (Theory)</strong> examination for Information Technology Grades 10–12. Each topic builds year-on-year, so it is important to master the foundational concepts before moving to more advanced content.</p><h2 id="what-s-in-this-section" tabindex="-1">What&#39;s in this section <a class="header-anchor" href="#what-s-in-this-section" aria-label="Permalink to &quot;What&#39;s in this section&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Topic</th><th>What you&#39;ll learn</th></tr></thead><tbody><tr><td><a href="./systems/">Systems Technologies</a></td><td>Hardware components, software, operating systems, performance, mobile tech, cloud and virtualisation</td></tr><tr><td><a href="./networks/">Communication Technologies</a></td><td>Network types, hardware, topologies, protocols, wireless networking and e-communication</td></tr><tr><td><a href="./internet/">Internet Technologies</a></td><td>How the internet and WWW work, web design, HTML, scripting and online services</td></tr><tr><td><a href="./databases/">Data &amp; Information Management</a></td><td>Data concepts, database design, normalisation, integrity and SQL theory</td></tr><tr><td><a href="./social/">Social Implications</a></td><td>Copyright, cybercrime, online safety, privacy, the digital divide and environmental impact</td></tr><tr><td><a href="./programming/">Solution Development (Theory)</a></td><td>Programming concepts, algorithms, OOP principles and software engineering theory</td></tr></tbody></table><h2 id="caps-alignment" tabindex="-1">CAPS alignment <a class="header-anchor" href="#caps-alignment" aria-label="Permalink to &quot;CAPS alignment&quot;">​</a></h2><p>All six topics are examined in <strong>Paper 2</strong> across Grades 10, 11 and 12. The depth and complexity increase each year:</p><ul><li><strong>Grade 10</strong> — Introduces foundational concepts and terminology.</li><li><strong>Grade 11</strong> — Extends understanding; students begin applying concepts in context.</li><li><strong>Grade 12</strong> — Requires synthesis, evaluation and application of all prior learning.</li></ul><p>Paper 2 is a <strong>written examination</strong> (no computer required). Expect definitions, short-answer questions, scenario analysis and diagram-based questions.</p>',8)])])}const g=t(o,[["render",i]]);export{m as __pageData,g as default};
